    p = os.environ.get('MANIFEST')
    if p and p.endswith('.json'):
        return json.load(open(p)).get('dependencies',{})
    if p:  # requirements.txt style
        out={}
        for line in open(p):
            line=line.strip()
            if line and not line.startswith('#'):
                m=re.split(r'[=<>~!]',line,1); out[m[0]]= line
